# In the drift detector main loop:
def notify_major_drift(report: DriftReport) -> None:
    httpx.post(
        SLACK_WEBHOOK_URL,
        json={
            "text": (
                f":rotating_light: *Template major version drift detected*\n"
                f"Service: *{report.service}* (owner: {report.owner})\n"
                f"Current template version: {report.service_version}\n"
                f"Latest template version: {report.current_version}\n"
                f"Action: *{report.action.upper()}* within 60 days\n"
                f"Migration guide: https://github.com/myorg/genai-template/blob/main/docs/migration/"
                f"v{report.service_version.split('.')[0]}-to-v{report.current_version.split('.')[0]}.md"
            )
        },
    )
